2842 Instruction *InstCombinerImpl::visitBranchInst(BranchInst &BI) {
2843   if (BI.isUnconditional())
2844     return visitUnconditionalBranchInst(BI);
2845 
2846   // Change br (not X), label True, label False to: br X, label False, True
2847   Value *Cond = BI.getCondition();
2848   Value *X;
2849   if (match(Cond, m_Not(m_Value(X))) && !isa<Constant>(X)) {
2850     // Swap Destinations and condition...
2851     BI.swapSuccessors();
2852     return replaceOperand(BI, 0, X);
2853   }
2854 
2855   // Canonicalize logical-and-with-invert as logical-or-with-invert.
2856   // This is done by inverting the condition and swapping successors:
2857   // br (X && !Y), T, F --> br !(X && !Y), F, T --> br (!X || Y), F, T
2858   Value *Y;
2859   if (isa<SelectInst>(Cond) &&
2860       match(Cond,
2861             m_OneUse(m_LogicalAnd(m_Value(X), m_OneUse(m_Not(m_Value(Y))))))) {
2862     Value *NotX = Builder.CreateNot(X, "not." + X->getName());
2863     Value *Or = Builder.CreateLogicalOr(NotX, Y);
2864     BI.swapSuccessors();
2865     return replaceOperand(BI, 0, Or);
2866   }
2867 
2868   // If the condition is irrelevant, remove the use so that other
2869   // transforms on the condition become more effective.
2870   if (!isa<ConstantInt>(Cond) && BI.getSuccessor(0) == BI.getSuccessor(1))
2871     return replaceOperand(BI, 0, ConstantInt::getFalse(Cond->getType()));
2872 
2873   // Canonicalize, for example, fcmp_one -> fcmp_oeq.
2874   CmpInst::Predicate Pred;
2875   if (match(Cond, m_OneUse(m_FCmp(Pred, m_Value(), m_Value()))) &&
2876       !isCanonicalPredicate(Pred)) {
2877     // Swap destinations and condition.
2878     auto *Cmp = cast<CmpInst>(Cond);
2879     Cmp->setPredicate(CmpInst::getInversePredicate(Pred));
2880     BI.swapSuccessors();
2881     Worklist.push(Cmp);
2882     return &BI;
2883   }
2884 
2885   if (isa<UndefValue>(Cond)) {
2886     handlePotentiallyDeadSuccessors(BI.getParent(), /*LiveSucc*/ nullptr);
2887     return nullptr;
2888   }
2889   if (auto *CI = dyn_cast<ConstantInt>(Cond)) {
2890     handlePotentiallyDeadSuccessors(BI.getParent(),
2891                                     BI.getSuccessor(!CI->getZExtValue()));
2892     return nullptr;
2893   }
2894 
2895   return nullptr;
2896 }
