2898 Instruction *InstCombinerImpl::visitSwitchInst(SwitchInst &SI) {
2899   Value *Cond = SI.getCondition();
2900   Value *Op0;
2901   ConstantInt *AddRHS;
2902   if (match(Cond, m_Add(m_Value(Op0), m_ConstantInt(AddRHS)))) {
2903     // Change 'switch (X+4) case 1:' into 'switch (X) case -3'.
2904     for (auto Case : SI.cases()) {
2905       Constant *NewCase = ConstantExpr::getSub(Case.getCaseValue(), AddRHS);
2906       assert(isa<ConstantInt>(NewCase) &&
2907              "Result of expression should be constant");
2908       Case.setValue(cast<ConstantInt>(NewCase));
2909     }
2910     return replaceOperand(SI, 0, Op0);
2911   }
2912 
2913   KnownBits Known = computeKnownBits(Cond, 0, &SI);
2914   unsigned LeadingKnownZeros = Known.countMinLeadingZeros();
2915   unsigned LeadingKnownOnes = Known.countMinLeadingOnes();
2916 
2917   // Compute the number of leading bits we can ignore.
2918   // TODO: A better way to determine this would use ComputeNumSignBits().
2919   for (const auto &C : SI.cases()) {
2920     LeadingKnownZeros =
2921         std::min(LeadingKnownZeros, C.getCaseValue()->getValue().countl_zero());
2922     LeadingKnownOnes =
2923         std::min(LeadingKnownOnes, C.getCaseValue()->getValue().countl_one());
2924   }
2925 
2926   unsigned NewWidth = Known.getBitWidth() - std::max(LeadingKnownZeros, LeadingKnownOnes);
2927 
2928   // Shrink the condition operand if the new type is smaller than the old type.
2929   // But do not shrink to a non-standard type, because backend can't generate
2930   // good code for that yet.
2931   // TODO: We can make it aggressive again after fixing PR39569.
2932   if (NewWidth > 0 && NewWidth < Known.getBitWidth() &&
2933       shouldChangeType(Known.getBitWidth(), NewWidth)) {
2934     IntegerType *Ty = IntegerType::get(SI.getContext(), NewWidth);
2935     Builder.SetInsertPoint(&SI);
2936     Value *NewCond = Builder.CreateTrunc(Cond, Ty, "trunc");
2937 
2938     for (auto Case : SI.cases()) {
2939       APInt TruncatedCase = Case.getCaseValue()->getValue().trunc(NewWidth);
2940       Case.setValue(ConstantInt::get(SI.getContext(), TruncatedCase));
2941     }
2942     return replaceOperand(SI, 0, NewCond);
2943   }
2944 
2945   if (isa<UndefValue>(Cond)) {
2946     handlePotentiallyDeadSuccessors(SI.getParent(), /*LiveSucc*/ nullptr);
2947     return nullptr;
2948   }
