4150 bool InstCombinerImpl::prepareWorklist(
4151     Function &F, ReversePostOrderTraversal<BasicBlock *> &RPOT) {
4152   bool MadeIRChange = false;
4153   SmallPtrSet<BasicBlock *, 32> LiveBlocks;
4154   SmallVector<Instruction *, 128> InstrsForInstructionWorklist;
4155   DenseMap<Constant *, Constant *> FoldedConstants;
4156   AliasScopeTracker SeenAliasScopes;
4157 
4158   auto HandleOnlyLiveSuccessor = [&](BasicBlock *BB, BasicBlock *LiveSucc) {
4159     for (BasicBlock *Succ : successors(BB))
4160       if (Succ != LiveSucc && DeadEdges.insert({BB, Succ}).second)
4161         for (PHINode &PN : Succ->phis())
4162           for (Use &U : PN.incoming_values())
4163             if (PN.getIncomingBlock(U) == BB && !isa<PoisonValue>(U)) {
4164               U.set(PoisonValue::get(PN.getType()));
4165               MadeIRChange = true;
4166             }
4167   };
4168 
4169   for (BasicBlock *BB : RPOT) {
4170     if (!BB->isEntryBlock() && all_of(predecessors(BB), [&](BasicBlock *Pred) {
4171           return DeadEdges.contains({Pred, BB}) || DT.dominates(BB, Pred);
4172         })) {
4173       HandleOnlyLiveSuccessor(BB, nullptr);
4174       continue;
4175     }
4176     LiveBlocks.insert(BB);
4177 
4178     for (Instruction &Inst : llvm::make_early_inc_range(*BB)) {
4179       // ConstantProp instruction if trivially constant.
4180       if (!Inst.use_empty() &&
4181           (Inst.getNumOperands() == 0 || isa<Constant>(Inst.getOperand(0))))
4182         if (Constant *C = ConstantFoldInstruction(&Inst, DL, &TLI)) {
4183           LLVM_DEBUG(dbgs() << "IC: ConstFold to: " << *C << " from: " << Inst
4184                             << '\n');
4185           Inst.replaceAllUsesWith(C);
4186           ++NumConstProp;
4187           if (isInstructionTriviallyDead(&Inst, &TLI))
4188             Inst.eraseFromParent();
4189           MadeIRChange = true;
4190           continue;
4191         }
4192 
4193       // See if we can constant fold its operands.
4194       for (Use &U : Inst.operands()) {
4195         if (!isa<ConstantVector>(U) && !isa<ConstantExpr>(U))
4196           continue;
4197 
4198         auto *C = cast<Constant>(U);
4199         Constant *&FoldRes = FoldedConstants[C];
4200         if (!FoldRes)
4201           FoldRes = ConstantFoldConstant(C, DL, &TLI);
4202 
4203         if (FoldRes != C) {
4204           LLVM_DEBUG(dbgs() << "IC: ConstFold operand of: " << Inst
4205                             << "\n    Old = " << *C
4206                             << "\n    New = " << *FoldRes << '\n');
4207           U = FoldRes;
4208           MadeIRChange = true;
4209         }
4210       }
4211 
4212       // Skip processing debug and pseudo intrinsics in InstCombine. Processing
4213       // these call instructions consumes non-trivial amount of time and
4214       // provides no value for the optimization.
4215       if (!Inst.isDebugOrPseudoInst()) {
4216         InstrsForInstructionWorklist.push_back(&Inst);
4217         SeenAliasScopes.analyse(&Inst);
4218       }
4219     }
4220 
4221     // If this is a branch or switch on a constant, mark only the single
4222     // live successor. Otherwise assume all successors are live.
4223     Instruction *TI = BB->getTerminator();
4224     if (BranchInst *BI = dyn_cast<BranchInst>(TI); BI && BI->isConditional()) {
4225       if (isa<UndefValue>(BI->getCondition())) {
4226         // Branch on undef is UB.
4227         HandleOnlyLiveSuccessor(BB, nullptr);
4228         continue;
4229       }
4230       if (auto *Cond = dyn_cast<ConstantInt>(BI->getCondition())) {
4231         bool CondVal = Cond->getZExtValue();
4232         HandleOnlyLiveSuccessor(BB, BI->getSuccessor(!CondVal));
4233         continue;
4234       }
4235     } else if (SwitchInst *SI = dyn_cast<SwitchInst>(TI)) {
4236       if (isa<UndefValue>(SI->getCondition())) {
4237         // Switch on undef is UB.
4238         HandleOnlyLiveSuccessor(BB, nullptr);
4239         continue;
4240       }
4241       if (auto *Cond = dyn_cast<ConstantInt>(SI->getCondition())) {
4242         HandleOnlyLiveSuccessor(BB,
4243                                 SI->findCaseValue(Cond)->getCaseSuccessor());
4244         continue;
4245       }
4246     }
4247   }
4248 
4249   // Remove instructions inside unreachable blocks. This prevents the
4250   // instcombine code from having to deal with some bad special cases, and
4251   // reduces use counts of instructions.
4252   for (BasicBlock &BB : F) {
4253     if (LiveBlocks.count(&BB))
4254       continue;
4255 
4256     unsigned NumDeadInstInBB;
4257     unsigned NumDeadDbgInstInBB;
4258     std::tie(NumDeadInstInBB, NumDeadDbgInstInBB) =
4259         removeAllNonTerminatorAndEHPadInstructions(&BB);
4260 
4261     MadeIRChange |= NumDeadInstInBB + NumDeadDbgInstInBB > 0;
4262     NumDeadInst += NumDeadInstInBB;
4263   }
4264 
4265   // Once we've found all of the instructions to add to instcombine's worklist,
4266   // add them in reverse order.  This way instcombine will visit from the top
4267   // of the function down.  This jives well with the way that it adds all uses
4268   // of instructions to the worklist after doing a transformation, thus avoiding
4269   // some N^2 behavior in pathological cases.
4270   Worklist.reserve(InstrsForInstructionWorklist.size());
4271   for (Instruction *Inst : reverse(InstrsForInstructionWorklist)) {
4272     // DCE instruction if trivially dead. As we iterate in reverse program
4273     // order here, we will clean up whole chains of dead instructions.
4274     if (isInstructionTriviallyDead(Inst, &TLI) ||
4275         SeenAliasScopes.isNoAliasScopeDeclDead(Inst)) {
4276       ++NumDeadInst;
4277       LLVM_DEBUG(dbgs() << "IC: DCE: " << *Inst << '\n');
4278       salvageDebugInfo(*Inst);
4279       Inst->eraseFromParent();
4280       MadeIRChange = true;
4281       continue;
4282     }
4283 
4284     Worklist.push(Inst);
4285   }
4286 
4287   return MadeIRChange;
4288 }
