4290 static bool combineInstructionsOverFunction(
4291     Function &F, InstructionWorklist &Worklist, AliasAnalysis *AA,
4292     AssumptionCache &AC, TargetLibraryInfo &TLI, TargetTransformInfo &TTI,
4293     DominatorTree &DT, OptimizationRemarkEmitter &ORE, BlockFrequencyInfo *BFI,
4294     ProfileSummaryInfo *PSI, unsigned MaxIterations, bool VerifyFixpoint,
4295     LoopInfo *LI) {
4296   auto &DL = F.getParent()->getDataLayout();
4297 
4298   /// Builder - This is an IRBuilder that automatically inserts new
4299   /// instructions into the worklist when they are created.
4300   IRBuilder<TargetFolder, IRBuilderCallbackInserter> Builder(
4301       F.getContext(), TargetFolder(DL),
4302       IRBuilderCallbackInserter([&Worklist, &AC](Instruction *I) {
4303         Worklist.add(I);
4304         if (auto *Assume = dyn_cast<AssumeInst>(I))
4305           AC.registerAssumption(Assume);
4306       }));
4307 
4308   ReversePostOrderTraversal<BasicBlock *> RPOT(&F.front());
4309 
4310   // Lower dbg.declare intrinsics otherwise their value may be clobbered
4311   // by instcombiner.
4312   bool MadeIRChange = false;
4313   if (ShouldLowerDbgDeclare)
4314     MadeIRChange = LowerDbgDeclare(F);
4315 
4316   // Iterate while there is work to do.
4317   unsigned Iteration = 0;
4318   while (true) {
4319     ++Iteration;
4320 
4321     if (Iteration > MaxIterations && !VerifyFixpoint) {
4322       LLVM_DEBUG(dbgs() << "\n\n[IC] Iteration limit #" << MaxIterations
4323                         << " on " << F.getName()
4324                         << " reached; stopping without verifying fixpoint\n");
4325       break;
4326     }
4327 
4328     ++NumWorklistIterations;
4329     LLVM_DEBUG(dbgs() << "\n\nINSTCOMBINE ITERATION #" << Iteration << " on "
4330                       << F.getName() << "\n");
4331 
4332     InstCombinerImpl IC(Worklist, Builder, F.hasMinSize(), AA, AC, TLI, TTI, DT,
4333                         ORE, BFI, PSI, DL, LI);
4334     IC.MaxArraySizeForCombine = MaxArraySize;
4335     bool MadeChangeInThisIteration = IC.prepareWorklist(F, RPOT);
4336     MadeChangeInThisIteration |= IC.run();
4337     if (!MadeChangeInThisIteration)
4338       break;
4339 
4340     MadeIRChange = true;
4341     if (Iteration > MaxIterations) {
4342       report_fatal_error(
4343           "Instruction Combining did not reach a fixpoint after " +
4344           Twine(MaxIterations) + " iterations");
4345     }
4346   }
4347 
4348   if (Iteration == 1)
4349     ++NumOneIteration;
4350   else if (Iteration == 2)
4351     ++NumTwoIterations;
4352   else if (Iteration == 3)
4353     ++NumThreeIterations;
4354   else
4355     ++NumFourOrMoreIterations;
4356 
4357   return MadeIRChange;
4358 }
