4382   //       callers in the pass pipeline explicitly set the option.
4383   auto *LI = AM.getCachedResult<LoopAnalysis>(F);
4384   if (!LI && Options.UseLoopInfo)
4385     LI = &AM.getResult<LoopAnalysis>(F);
4386 
4387   auto *AA = &AM.getResult<AAManager>(F);
4388   auto &MAMProxy = AM.getResult<ModuleAnalysisManagerFunctionProxy>(F);
4389   ProfileSummaryInfo *PSI =
4390       MAMProxy.getCachedResult<ProfileSummaryAnalysis>(*F.getParent());
4391   auto *BFI = (PSI && PSI->hasProfileSummary()) ?
4392       &AM.getResult<BlockFrequencyAnalysis>(F) : nullptr;
4393 
4394   if (!combineInstructionsOverFunction(F, Worklist, AA, AC, TLI, TTI, DT, ORE,
4395                                        BFI, PSI, Options.MaxIterations,
4396                                        Options.VerifyFixpoint, LI))
4397     // No changes, all analyses are preserved.
4398     return PreservedAnalyses::all();
