406   /// Combiner aware instruction erasure.
407   ///
408   /// When dealing with an instruction that has side effects or produces a void
409   /// value, we can't rely on DCE to delete the instruction. Instead, visit
410   /// methods should return the value returned by this function.
411   Instruction *eraseInstFromFunction(Instruction &I) override {
412     LLVM_DEBUG(dbgs() << "IC: ERASE " << I << '\n');
413     assert(I.use_empty() && "Cannot erase instruction that is used!");
414     salvageDebugInfo(I);
415 
416     // Make sure that we reprocess all operands now that we reduced their
417     // use counts.
418     SmallVector<Value *> Ops(I.operands());
419     Worklist.remove(&I);
420     I.eraseFromParent();
421     for (Value *Op : Ops)
422       Worklist.handleUseCountDecrement(Op);
423     MadeIRChange = true;
424     return nullptr; // Don't do anything with FI
425   }
